def _base_layout():
    t = T()
    return dict(
        font=dict(family="Inter, -apple-system, sans-serif", color=t["text"], size=11),
        paper_bgcolor=t["chart_paper"], plot_bgcolor=t["chart_bg"],
        margin=dict(l=50, r=10, t=25, b=25),
        legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="left", x=0,
                    font=dict(color=t["text"], size=10)),
        xaxis=dict(gridcolor=t["grid"], zeroline=False, color=t["text_muted"]),
        yaxis=dict(gridcolor=t["grid"], zeroline=False, color=t["text_muted"]),
    )

def _layout(**kw):
    d = _base_layout(); d.update(kw); return d


