def _strategy_number_map(results_df):
    combos = results_df[["x", "y", "window"]].drop_duplicates()
    combos = combos.sort_values(["x", "y", "window"]).reset_index(drop=True)
    return {(int(r.x), int(r.y), int(r.window)): i + 1 for i, r in combos.iterrows()}


