# ═══════════════════════════════════════════════
# TAB: STRATEGIES
# ═══════════════════════════════════════════════

def tab_strategies(results_df, all_strats, best_key, strat_num_map, tips):
    t = T()
    sel_x = st.session_state.sel_x
    sel_y = st.session_state.sel_y
    sel_win = st.session_state.sel_win
    key = (sel_x, sel_y, sel_win)
    strat = all_strats.get(key)
    if strat is None:
        strat = all_strats[best_key]; key = best_key

    chart_data = strat["chart_data"]
    strat_num = strat_num_map.get(key, 0)

    # Prepare metric/window options
    windows = sorted(results_df["window"].unique())
    metric_map = {}
    for dn, ik, sfx, _ in _METRIC_ORDER:
        lbl = dn.replace(" %", " (%)") if sfx == "%" else dn
        metric_map[lbl] = ik
    metric_keys = list(metric_map.keys())
    calmar_idx = next(i for i, k in enumerate(metric_keys) if "Calmar" in k)

    render_selected_label(key, strat_num, tips)

    # ══ Row 1: Heatmap (with selectors) | Equity Curve | Drawdown ══
    col_hm, col_eq, col_dd = st.columns(3)

    with col_hm:
        _section_title("Strategy Heatmap", tips)
        # Side-by-side compact selectors inside the heatmap box
        dd_cols = st.columns([2, 1])
        with dd_cols[0]:
            sel_metric_label = st.selectbox(
                "Performance Metric", metric_keys, index=calmar_idx,
                help=tips.get("Strategy Heatmap", ""),
                key="hm_metric")
            sel_metric = metric_map[sel_metric_label]
        with dd_cols[1]:
            hm_win = st.selectbox("Window (z)", windows,
                                   index=windows.index(sel_win) if sel_win in windows else 0,
                                   help=tips.get("Window (z)", ""),
                                   key="hm_window")

        fig_hm = make_heatmap(results_df, sel_metric, sel_metric_label, hm_win,
                              sel_x, sel_y, sel_win)
        hm_event = st.plotly_chart(fig_hm, on_select="rerun",
                                    key="heatmap_click", width="stretch",
                                    selection_mode=["points"],
                                    config={"displaylogo": False,
                                            "modeBarButtonsToRemove": ["lasso2d"]})

        if hm_event and hm_event.selection and hm_event.selection.points:
            pt = hm_event.selection.points[0]
            cd_pt = pt.get("customdata")
            if cd_pt and isinstance(cd_pt, (list, tuple)) and len(cd_pt) >= 2:
                new_x, new_y = int(cd_pt[0]), int(cd_pt[1])
            else:
                try:
                    new_x, new_y = int(pt["x"]), int(pt["y"])
                except (ValueError, KeyError, TypeError):
                    new_x, new_y = sel_x, sel_y
            if new_x != sel_x or new_y != sel_y or hm_win != sel_win:
                st.session_state.sel_x = new_x
                st.session_state.sel_y = new_y
                st.session_state.sel_win = hm_win
                st.session_state.sel_trade_idx = 0
                st.rerun()

    with col_eq:
        _section_title("Equity Curve", tips)
        st.plotly_chart(make_equity(chart_data, compact=True), width="stretch",
                        config={"displaylogo": False})

    with col_dd:
        _section_title("Drawdown", tips)
        st.plotly_chart(make_drawdown(chart_data, compact=True), width="stretch",
                        config={"displaylogo": False})

    # ══ Row 2: Strategy Table (full width) ══
    _section_title("Strategy Table", tips)

    internal_cols = [mk for _, mk, _, _ in _METRIC_ORDER]
    display_names = [dn for dn, _, _, _ in _METRIC_ORDER]

    display_df = results_df[["x", "y", "window"] + internal_cols].copy()
    display_df["alpha"] = display_df["alpha"] / 100.0
    display_df.columns = ["Buy (x)", "Sell (y)", "Window (z)"] + display_names
    display_df = display_df.sort_values("Calmar Ratio", ascending=False).reset_index(drop=True)

    display_df.insert(0, "Strategy", display_df.apply(
        lambda r: strat_num_map.get((int(r["Buy (x)"]), int(r["Sell (y)"]), int(r["Window (z)"])), 0),
        axis=1))

    for dn, _, sfx, _ in _METRIC_ORDER:
        if sfx == "%":
            display_df[dn] = display_df[dn].round(1)
        elif dn == "Trades":
            display_df[dn] = display_df[dn].astype(int)
        else:
            display_df[dn] = display_df[dn].round(2)
    display_df["Trades"] = display_df["Trades"].astype(int)

    # Pin selected strategy to top
    sel_strat_num = strat_num_map.get(key, 0)
    sel_mask = display_df["Strategy"] == sel_strat_num
    if sel_mask.any():
        sel_row = display_df[sel_mask]
        rest = display_df[~sel_mask]
        display_df = pd.concat([sel_row, rest], ignore_index=True)

    # Select checkbox — True for first row (selected via heatmap or table)
    display_df.insert(0, "Select", False)
    if len(display_df) > 0:
        display_df.at[0, "Select"] = True

    # Column config with tooltips and number formats
    col_config = {
        "Select": st.column_config.CheckboxColumn("Select", width="small"),
        "Strategy": st.column_config.NumberColumn("Strategy",
                     help=tips.get("Strategy", ""), width="small", format="%d"),
        "Buy (x)": st.column_config.NumberColumn("Buy (x)", help=tips.get("Buy (x)", ""), format="%d"),
        "Sell (y)": st.column_config.NumberColumn("Sell (y)", help=tips.get("Sell (y)", ""), format="%d"),
        "Window (z)": st.column_config.NumberColumn("Window (z)", help=tips.get("Window (z)", ""), format="%d"),
    }
    for dn, _, sfx, _ in _METRIC_ORDER:
        tip = tips.get(dn, "")
        if dn == "Trades":
            col_config[dn] = st.column_config.NumberColumn(dn, help=tip, format="%d")
        elif sfx == "%":
            col_config[dn] = st.column_config.NumberColumn(dn, help=tip, format="%.1f")
        else:
            col_config[dn] = st.column_config.NumberColumn(dn, help=tip, format="%.2f")

    edited_df = st.data_editor(
        display_df,
        hide_index=True, height=290, width="stretch",
        key="strat_tbl",
        column_config=col_config,
        disabled=[c for c in display_df.columns if c != "Select"],
    )

    # Detect checkbox change
    if edited_df is not None:
        checked = edited_df[edited_df["Select"] == True]
        if len(checked) > 0:
            pick = checked.iloc[-1]
            new_x, new_y, new_win = int(pick["Buy (x)"]), int(pick["Sell (y)"]), int(pick["Window (z)"])
            if new_x != sel_x or new_y != sel_y or new_win != sel_win:
                st.session_state.sel_x = new_x
                st.session_state.sel_y = new_y
                st.session_state.sel_win = new_win
                st.session_state.sel_trade_idx = 0
                st.rerun()


# ═══════════════════════════════════════════════
# TAB: TRADES
# ═══════════════════════════════════════════════

def tab_trades(all_strats, best_key, strat_num_map, tips):
    t = T()
    sel_x = st.session_state.sel_x
    sel_y = st.session_state.sel_y
    sel_win = st.session_state.sel_win
    key = (sel_x, sel_y, sel_win)
    strat = all_strats.get(key)
    if strat is None:
        strat = all_strats[best_key]; key = best_key

    trades = strat["trades"]
    metrics = strat["metrics"]
    chart_data = strat["chart_data"]
    strat_num = strat_num_map.get(key, 0)

    render_selected_label(key, strat_num, tips)

    _section_title("KPIs", tips)
    render_trades_kpis(metrics, tips)

    LOG_H, CHART_H = 380, 380
    col_log, col_chart = st.columns(2)

    with col_log:
        _section_title("Trade Log", tips)
        if trades:
            trades_df = pd.DataFrame(trades)
            trades_df.columns = ["Trade", "Entry Date", "Entry Price", "Exit Date",
                                 "Exit Price", "PnL ($)", "Return (%)", "Status"]
            trades_df["Duration"] = (
                pd.to_datetime(trades_df["Exit Date"]) - pd.to_datetime(trades_df["Entry Date"])
            ).dt.days
            trades_df = trades_df.drop(columns=["Status"])

            def color_return(val):
                if isinstance(val, (int, float)):
                    if val > 0: return f"color: {t['green']}"
                    if val < 0: return f"color: {t['red']}"
                return ""

            log_event = st.dataframe(
                trades_df.style
                .map(color_return, subset=["PnL ($)", "Return (%)"])
                .format({"Entry Price": "${:,.2f}", "Exit Price": "${:,.2f}",
                         "PnL ($)": "${:,.2f}", "Return (%)": "{:.2f}%"}),
                width="stretch", height=LOG_H,
                on_select="rerun", selection_mode="single-row",
                key="trade_table",
            )

            trade_idx = st.session_state.sel_trade_idx
            if log_event and log_event.selection and log_event.selection.rows:
                trade_idx = log_event.selection.rows[0]
                st.session_state.sel_trade_idx = trade_idx
        else:
            st.info("No trades generated for this parameter combination.")
            trade_idx = -1

    with col_chart:
        _section_title("Trade Analysis", tips)
        if trades and 0 <= st.session_state.sel_trade_idx < len(trades):
            sel_trade = trades[st.session_state.sel_trade_idx]
            st.plotly_chart(make_single_trade(sel_trade, chart_data,
                                              sel_x=sel_x, sel_y=sel_y, height=CHART_H),
                            width="stretch", config={"displaylogo": False})
        else:
            st.info("Select a trade to zoom in.")


